using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var modelName = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";
var apiKey    = Environment.GetEnvironmentVariable("OPENAI_API_KEY") ?? "";

if (string.IsNullOrWhiteSpace(apiKey))
{
    Console.Error.WriteLine("Error: Set the OPENAI_API_KEY environment variable.");
    return 1;
}

// ---------------------------------------------------------------------------
// Tools the agent can call
// ---------------------------------------------------------------------------
var researchTools = new ResearchTools();

var tools = new AITool[]
{
    AIFunctionFactory.Create(researchTools.SearchWeb),
    AIFunctionFactory.Create(researchTools.TakeNote),
    AIFunctionFactory.Create(researchTools.GetNotes),
};

// ---------------------------------------------------------------------------
// Chat client with automatic function-calling
// ---------------------------------------------------------------------------
IChatClient client = new OpenAIClient(apiKey)
    .GetChatClient(modelName)
    .AsIChatClient()
    .AsBuilder()
    .UseFunctionInvocation()
    .Build();

var chatOptions = new ChatOptions { Tools = [.. tools] };

// ---------------------------------------------------------------------------
// Agent loop
// ---------------------------------------------------------------------------
Console.WriteLine("=== Research Agent ===");
Console.WriteLine("Enter a topic to research (or 'quit' to exit):\n");

while (true)
{
    Console.ForegroundColor = ConsoleColor.Cyan;
    Console.Write("> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    researchTools.ClearNotes();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, """
            You are a research agent. When the user gives you a topic:
            1. Use the SearchWeb tool multiple times with different queries to gather information.
            2. Use the TakeNote tool to record important findings as you go.
            3. After gathering enough information, use GetNotes to review everything you collected.
            4. Finally, provide a well-structured summary of your research to the user.
            Be thorough — search at least 3 different angles of the topic.
            """),
        new(ChatRole.User, $"Research the following topic and provide a summary: {topic}"),
    };

    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("\nResearching…\n");
    Console.ResetColor();

    try
    {
        var response = await client.GetResponseAsync(messages, chatOptions);
        Console.ForegroundColor = ConsoleColor.Green;
        Console.WriteLine(response.Text);
        Console.ResetColor();
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }
}

return 0;

// ===========================================================================
// Tool implementations
// ===========================================================================
sealed class ResearchTools
{
    private readonly List<string> _notes = [];

    /// <summary>Clears all notes for a new research session.</summary>
    public void ClearNotes() => _notes.Clear();

    // -----------------------------------------------------------------------
    // Web search tool — simulates searching the web for information.
    // Replace the body with a real search API (Bing, Google, Brave, etc.)
    // when you have an API key.
    // -----------------------------------------------------------------------
    [Description("Searches the web for the given query and returns a list of result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        await Task.Delay(250); // simulate network latency

        // In production, call a real search API here.  The placeholder below
        // returns representative results so the agent loop works end-to-end
        // without requiring a second API key.
        var results = new[]
        {
            new { Title = $"Overview of {query}",           Snippet = $"An in-depth look at {query}: key concepts, recent developments, and expert analysis." },
            new { Title = $"Latest research on {query}",    Snippet = $"Recent studies and findings related to {query}, covering breakthroughs and ongoing debates." },
            new { Title = $"{query} — practical insights",  Snippet = $"Practical applications and real-world implications of {query}, with case studies and data." },
        };

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🔍  Searched: \"{query}\"  ({results.Length} results)");
        Console.ResetColor();

        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }

    // -----------------------------------------------------------------------
    // Note-taking tool — lets the agent record important findings.
    // -----------------------------------------------------------------------
    [Description("Records a research note for later review. Use this to save important findings.")]
    public string TakeNote(
        [Description("The note text to save")] string note)
    {
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝  Note #{_notes.Count} saved");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved successfully.";
    }

    // -----------------------------------------------------------------------
    // Retrieve all notes — so the agent can review before summarizing.
    // -----------------------------------------------------------------------
    [Description("Retrieves all research notes taken so far.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋  Retrieved {_notes.Count} note(s)");
        Console.ResetColor();

        return string.Join("\n\n",
            _notes.Select((n, i) => $"Note #{i + 1}: {n}"));
    }
}

